/* eslint-disable react-hooks/exhaustive-deps */
import React, { useEffect, useState } from "react";
import { BASE } from "./api";

export default function AdminPanel() {
  const [loading, setLoading] = useState(false);
  const [users, setUsers] = useState([]);
  const [posts, setPosts] = useState([]);
  const [reports, setReports] = useState([]);
  const [comments, setComments] = useState([]);
  const [messages, setMessages] = useState([]);
  const [modal, setModal] = useState(null);
  const [activeTab, setActiveTab] = useState("dashboard");
  const [editingId, setEditingId] = useState(null);
  const [editingContent, setEditingContent] = useState("");
  const [stats, setStats] = useState({
    totalUsers: 0,
    totalPosts: 0,
    totalReports: 0,
    totalComments: 0,
    bannedUsers: 0,
    resolvedReports: 0
  });

  const token = localStorage.getItem("token");

  // ---------- MODAL ----------
  const showModal = (msg, onYes) => setModal({ msg, onYes });
  const closeModal = () => setModal(null);

  // ---------- FETCH ----------
  const fetchAdminUsers = async () => {
    try {
      const res = await fetch(`${BASE}/api/admin/users`, {
        headers: { Authorization: `Bearer ${token}` },
      });
      const data = await res.json();
      const usersList = Array.isArray(data) ? data : data.data || [];
      setUsers(usersList);
      return usersList.length;
    } catch (err) {
      console.error(err);
      setUsers([]);
      return 0;
    }
  };

  const fetchPosts = async () => {
    try {
      const res = await fetch(`${BASE}/api/posts`);
      const data = await res.json();
      const postsList = data.data?.posts || data.posts || data || [];
      const postsArray = Array.isArray(postsList) ? postsList : [];
      setPosts(postsArray);
      return postsArray.length;
    } catch (err) {
      console.error(err);
      setPosts([]);
      return 0;
    }
  };

  const fetchReports = async () => {
    try {
      const res = await fetch(`${BASE}/api/reports`, {
        headers: { Authorization: `Bearer ${token}` },
      });
      const data = await res.json();
      const reportsList = Array.isArray(data.data) ? data.data : [];
      setReports(reportsList);
      return reportsList.length;
    } catch (err) {
      console.error(err);
      setReports([]);
      return 0;
    }
  };

  const fetchComments = async () => {
    try {
      const res = await fetch(`${BASE}/api/comments`, {
        headers: { Authorization: `Bearer ${token}` },
      });
      const data = await res.json();
      const commentsList = Array.isArray(data.data) ? data.data : Array.isArray(data) ? data : [];
      setComments(commentsList);
      return commentsList.length;
    } catch (err) {
      console.error(err);
      setComments([]);
      return 0;
    }
  };

  const fetchMessages = async () => {
    try {
      const res = await fetch(`${BASE}/api/messages`, {
        headers: { Authorization: `Bearer ${token}` },
      });
      const data = await res.json();
      const messagesList = Array.isArray(data.data) ? data.data : Array.isArray(data) ? data : [];
      setMessages(messagesList);
      return messagesList.length;
    } catch (err) {
      console.error(err);
      setMessages([]);
      return 0;
    }
  };

  const refreshAll = async () => {
    setLoading(true);
    await Promise.all([
      fetchAdminUsers(),
      fetchPosts(),
      fetchReports(),
      fetchComments(),
      fetchMessages()
    ]);
    
    setStats(prev => ({
      ...prev,
      totalUsers: users.length,
      totalPosts: posts.length,
      totalReports: reports.length,
      totalComments: comments.length,
      bannedUsers: users.filter(u => u.status === 'banned' || u.is_banned).length,
      resolvedReports: reports.filter(r => r.status === 'resolved' || r.resolved).length
    }));
    
    setLoading(false);
  };

  useEffect(() => {
    refreshAll();
  }, []);

  // ---------- ACTIONS ----------
  const banUser = (id) =>
    showModal("Ban user này?", async () => {
      try {
        await fetch(`${BASE}/api/admin/user/${id}/ban`, {
          method: "PUT",
          headers: { Authorization: `Bearer ${token}` },
        });
        closeModal();
        await fetchAdminUsers();
      } catch (err) {
        console.error('Ban user error:', err);
      }
    });

  const deletePost = (id) =>
    showModal("Xóa bài viết này?", async () => {
      try {
        await fetch(`${BASE}/api/admin/post/${id}`, {
          method: "DELETE",
          headers: { Authorization: `Bearer ${token}` },
        });
        closeModal();
        await fetchPosts();
      } catch (err) {
        console.error('Delete post error:', err);
      }
    });

  const deleteComment = (id) =>
    showModal("Xóa bình luận này?", async () => {
      try {
        await fetch(`${BASE}/api/admin/comment/${id}`, {
          method: "DELETE",
          headers: { Authorization: `Bearer ${token}` },
        });
        closeModal();
        await fetchComments();
      } catch (err) {
        console.error('Delete comment error:', err);
      }
    });

  const deleteMessage = (id) =>
    showModal("Xóa tin nhắn này?", async () => {
      try {
        await fetch(`${BASE}/api/admin/message/${id}`, {
          method: "DELETE",
          headers: { Authorization: `Bearer ${token}` },
        });
        closeModal();
        await fetchMessages();
      } catch (err) {
        console.error('Delete message error:', err);
      }
    });

  const editPost = (id, content) => {
    setEditingId(id);
    setEditingContent(content);
  };

  const editComment = (id, content) => {
    setEditingId(id);
    setEditingContent(content);
  };

  const editMessage = (id, content) => {
    setEditingId(id);
    setEditingContent(content);
  };

  const saveEdit = async (type, id) => {
    if (!editingContent.trim()) {
      closeModal();
      return;
    }
    
    const endpoints = {
      post: `${BASE}/api/admin/post/${id}`,
      comment: `${BASE}/api/admin/comment/${id}`,
      message: `${BASE}/api/admin/message/${id}`
    };

    try {
      await fetch(endpoints[type], {
        method: "PUT",
        headers: {
          Authorization: `Bearer ${token}`,
          "Content-Type": "application/json"
        },
        body: JSON.stringify({ 
          content: editingContent,
          text: editingContent 
        })
      });
      
      setEditingId(null);
      setEditingContent("");
      
      if (type === "post") await fetchPosts();
      if (type === "comment") await fetchComments();
      if (type === "message") await fetchMessages();
    } catch (err) {
      console.error(`Edit ${type} error:`, err);
    }
  };

  const resolveReport = (id) =>
    showModal("Đánh dấu đã xử lý?", async () => {
      try {
        await fetch(`${BASE}/api/admin/report/${id}/resolve`, {
          method: "PUT",
          headers: { Authorization: `Bearer ${token}` },
        });
        closeModal();
        await fetchReports();
      } catch (err) {
        console.error('Resolve report error:', err);
      }
    });

  // Stat Card Component
  const StatCard = ({ title, count, icon, color }) => (
    <div className={`bg-gradient-to-br ${color} rounded-xl p-6 text-white shadow-lg`}>
      <div className="flex items-center justify-between">
        <div>
          <p className="text-sm opacity-90 font-medium">{title}</p>
          <p className="text-4xl font-bold mt-2">{count}</p>
        </div>
        <div className="text-6xl opacity-20">{icon}</div>
      </div>
    </div>
  );

  return (
    <div className="min-h-screen bg-gradient-to-br from-slate-900 via-slate-800 to-slate-900 px-4 py-6">
      <div className="max-w-7xl mx-auto">
        {/* Header */}
        <div className="mb-8">
          <h1 className="text-5xl font-bold text-white flex items-center gap-3 mb-2">
            <svg className="w-12 h-12 text-red-500" fill="currentColor" viewBox="0 0 20 20">
              <path fillRule="evenodd" d="M11.3 1.046A1 1 0 0112 2v5h4a1 1 0 01.82 1.573l-7 10A1 1 0 018 17v-5H4a1 1 0 01-.82-1.573l7-10a1 1 0 011.12-.381z" clipRule="evenodd" />
            </svg>
            Admin Dashboard
          </h1>
          <p className="text-gray-400">Quản lý toàn bộ hệ thống</p>
        </div>

        {/* Tab Navigation */}
        <div className="flex gap-2 mb-6 overflow-x-auto pb-2">
          {[
            { id: 'dashboard', label: '📊 Thống kê', icon: '📊' },
            { id: 'users', label: '👥 Người dùng', icon: '👥' },
            { id: 'posts', label: '📝 Bài viết', icon: '📝' },
            { id: 'comments', label: '💬 Bình luận', icon: '💬' },
            { id: 'messages', label: '✉️ Tin nhắn', icon: '✉️' },
            { id: 'reports', label: '🚨 Báo cáo', icon: '🚨' },
            { id: 'media', label: '🖼️ Media', icon: '🖼️' },
          ].map(tab => (
            <button
              key={tab.id}
              onClick={() => setActiveTab(tab.id)}
              className={`px-6 py-3 rounded-lg font-semibold transition-all whitespace-nowrap ${
                activeTab === tab.id
                  ? 'bg-gradient-to-r from-red-500 to-pink-600 text-white shadow-lg'
                  : 'bg-slate-700 text-gray-300 hover:bg-slate-600'
              }`}
            >
              {tab.label}
            </button>
          ))}
        </div>

        {/* Refresh Button */}
        <button
          className="w-full bg-gradient-to-r from-blue-500 to-blue-600 hover:from-blue-600 hover:to-blue-700 text-white font-semibold px-4 py-3 rounded-xl shadow-lg transition-all flex items-center justify-center gap-2 mb-6"
          onClick={refreshAll}
          disabled={loading}
        >
          <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
          </svg>
          {loading ? 'Đang tải...' : 'Làm mới dữ liệu'}
        </button>

        {/* Dashboard Tab */}
        {activeTab === 'dashboard' && (
          <div className="space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
              <StatCard title="Tổng người dùng" count={stats.totalUsers} icon="👤" color="from-blue-500 to-blue-600" />
              <StatCard title="Tổng bài viết" count={stats.totalPosts} icon="📝" color="from-green-500 to-green-600" />
              <StatCard title="Tổng bình luận" count={stats.totalComments} icon="💬" color="from-purple-500 to-purple-600" />
              <StatCard title="Báo cáo (chưa xử lý)" count={stats.totalReports - stats.resolvedReports} icon="⚠️" color="from-orange-500 to-orange-600" />
              <StatCard title="Người dùng bị ban" count={stats.bannedUsers} icon="🚫" color="from-red-500 to-red-600" />
              <StatCard title="Báo cáo (đã xử lý)" count={stats.resolvedReports} icon="✅" color="from-emerald-500 to-emerald-600" />
            </div>
            
            <div className="bg-gradient-to-r from-slate-700 to-slate-800 rounded-2xl p-8 text-center">
              <h3 className="text-2xl font-bold text-white mb-4">Tóm tắt hệ thống</h3>
              <p className="text-gray-400 mb-6">Tổng cộng: {stats.totalUsers + stats.totalPosts + stats.totalComments + stats.totalReports} mục dữ liệu</p>
              <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                <div className="bg-slate-600 rounded-lg p-4">
                  <p className="text-gray-300 text-sm">Tỷ lệ ban</p>
                  <p className="text-2xl font-bold text-red-400">{stats.totalUsers > 0 ? ((stats.bannedUsers / stats.totalUsers) * 100).toFixed(1) : 0}%</p>
                </div>
                <div className="bg-slate-600 rounded-lg p-4">
                  <p className="text-gray-300 text-sm">Tỷ lệ báo cáo đã xử lý</p>
                  <p className="text-2xl font-bold text-green-400">{stats.totalReports > 0 ? ((stats.resolvedReports / stats.totalReports) * 100).toFixed(1) : 0}%</p>
                </div>
                <div className="bg-slate-600 rounded-lg p-4">
                  <p className="text-gray-300 text-sm">Bài viết/Người dùng</p>
                  <p className="text-2xl font-bold text-blue-400">{stats.totalUsers > 0 ? (stats.totalPosts / stats.totalUsers).toFixed(2) : 0}</p>
                </div>
                <div className="bg-slate-600 rounded-lg p-4">
                  <p className="text-gray-300 text-sm">Bình luận/Bài viết</p>
                  <p className="text-2xl font-bold text-purple-400">{stats.totalPosts > 0 ? (stats.totalComments / stats.totalPosts).toFixed(2) : 0}</p>
                </div>
              </div>
            </div>
          </div>
        )}

        {/* Users Tab */}
        {activeTab === 'users' && (
          <div className="bg-white rounded-2xl shadow-lg overflow-hidden">
            <div className="bg-gradient-to-r from-blue-500 to-blue-600 px-6 py-4 flex items-center gap-3">
              <svg className="w-6 h-6 text-white" fill="currentColor" viewBox="0 0 20 20">
                <path d="M9 6a3 3 0 11-6 0 3 3 0 016 0zM9 6a3 3 0 11-6 0 3 3 0 016 0zM9 6a3 3 0 11-6 0 3 3 0 016 0zM17 6a3 3 0 11-6 0 3 3 0 016 0z" />
                <path d="M2 13a6 6 0 0112 0v3H2v-3zm6-6h.01M17 13a6 6 0 01-12 0" />
              </svg>
              <h2 className="text-2xl font-bold text-white">Quản lý người dùng ({users.length})</h2>
            </div>
            <div className="divide-y divide-gray-200 max-h-96 overflow-y-auto">
              {users.length === 0 ? (
                <div className="p-8 text-center text-gray-500">
                  <svg className="w-12 h-12 text-gray-300 mx-auto mb-3" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M17 20h5v-2a3 3 0 00-5.856-1.487M15 10a3 3 0 11-6 0 3 3 0 016 0z" />
                  </svg>
                  Không có user
                </div>
              ) : (
                users.map((u) => (
                  <div key={u.id} className="px-6 py-4 hover:bg-blue-50 transition-colors flex justify-between items-center">
                    <div className="flex-1">
                      <p className="font-semibold text-gray-900">{u.full_name || u.username}</p>
                      <p className="text-sm text-gray-600">{u.email}</p>
                      <span className={`inline-block mt-1 px-3 py-1 rounded-full text-xs font-semibold ${u.status === 'banned' || u.is_banned ? 'bg-red-100 text-red-700' : 'bg-green-100 text-green-700'}`}>
                        {u.status === 'banned' || u.is_banned ? 'Bị ban' : 'Hoạt động'}
                      </span>
                    </div>
                    <button
                      className="bg-red-500 hover:bg-red-600 text-white font-semibold px-4 py-2 rounded-lg transition-all"
                      onClick={() => banUser(u.id)}
                    >
                      Ban
                    </button>
                  </div>
                ))
              )}
            </div>
          </div>
        )}

        {/* Posts Tab */}
        {activeTab === 'posts' && (
          <div className="bg-white rounded-2xl shadow-lg overflow-hidden">
            <div className="bg-gradient-to-r from-purple-500 to-purple-600 px-6 py-4 flex items-center gap-3">
              <svg className="w-6 h-6 text-white" fill="currentColor" viewBox="0 0 20 20">
                <path d="M2 5a2 2 0 012-2h12a2 2 0 012 2v10a2 2 0 01-2 2H4a2 2 0 01-2-2V5z" />
              </svg>
              <h2 className="text-2xl font-bold text-white">Quản lý bài viết ({posts.length})</h2>
            </div>
            <div className="divide-y divide-gray-200 max-h-96 overflow-y-auto">
              {posts.length === 0 ? (
                <div className="p-8 text-center text-gray-500">
                  <svg className="w-12 h-12 text-gray-300 mx-auto mb-3" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
                  </svg>
                  Không có bài viết
                </div>
              ) : (
                posts.map((p) => (
                  <div key={p.id} className="px-6 py-4 hover:bg-purple-50 transition-colors">
                    {editingId === p.id ? (
                      <div className="space-y-2 mb-3">
                        <textarea
                          value={editingContent}
                          onChange={(e) => setEditingContent(e.target.value)}
                          className="w-full p-2 border border-gray-300 rounded text-sm"
                          rows="3"
                        />
                        <div className="flex gap-2">
                          <button
                            className="bg-blue-500 hover:bg-blue-600 text-white font-semibold px-3 py-1 rounded text-sm"
                            onClick={() => saveEdit('post', p.id)}
                          >
                            Lưu
                          </button>
                          <button
                            className="bg-gray-300 hover:bg-gray-400 text-gray-800 font-semibold px-3 py-1 rounded text-sm"
                            onClick={() => setEditingId(null)}
                          >
                            Hủy
                          </button>
                        </div>
                      </div>
                    ) : (
                      <p className="font-semibold text-gray-900 mb-1 line-clamp-2">{p.content || p.text || '(Không có nội dung)'}</p>
                    )}
                    <p className="text-sm text-gray-600 mb-3">bởi @{p.user?.username || p.User?.username || 'unknown'}</p>
                    <div className="flex gap-2">
                      <button
                        className="bg-blue-500 hover:bg-blue-600 text-white font-semibold px-3 py-1 rounded text-sm"
                        onClick={() => editPost(p.id, p.content || p.text || '')}
                      >
                        Sửa
                      </button>
                      <button
                        className="bg-red-500 hover:bg-red-600 text-white font-semibold px-3 py-1 rounded text-sm"
                        onClick={() => deletePost(p.id)}
                      >
                        Xóa
                      </button>
                    </div>
                  </div>
                ))
              )}
            </div>
          </div>
        )}

        {/* Comments Tab */}
        {activeTab === 'comments' && (
          <div className="bg-white rounded-2xl shadow-lg overflow-hidden">
            <div className="bg-gradient-to-r from-green-500 to-green-600 px-6 py-4 flex items-center gap-3">
              <svg className="w-6 h-6 text-white" fill="currentColor" viewBox="0 0 20 20">
                <path d="M2 5a2 2 0 012-2h12a2 2 0 012 2v10a2 2 0 01-2 2H4a2 2 0 01-2-2V5z" />
                <path fillRule="evenodd" d="M3 7a1 1 0 011-1h12a1 1 0 110 2H4a1 1 0 01-1-1zm0 4a1 1 0 011-1h12a1 1 0 110 2H4a1 1 0 01-1-1z" clipRule="evenodd" />
              </svg>
              <h2 className="text-2xl font-bold text-white">Quản lý bình luận ({comments.length})</h2>
            </div>
            <div className="divide-y divide-gray-200 max-h-96 overflow-y-auto">
              {comments.length === 0 ? (
                <div className="p-8 text-center text-gray-500">
                  <svg className="w-12 h-12 text-gray-300 mx-auto mb-3" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M8 12h.01M12 12h.01M16 12h.01M21 12c0 4.418-4.03 8-9 8a9.863 9.863 0 01-4.255-.949L3 20l1.395-3.72C3.512 15.042 3 13.574 3 12c0-4.418 4.03-8 9-8s9 3.582 9 8z" />
                  </svg>
                  Không có bình luận
                </div>
              ) : (
                comments.map((c) => (
                  <div key={c.id} className="px-6 py-4 hover:bg-green-50 transition-colors">
                    <p className="text-sm text-gray-600 mb-2 font-semibold">{c.User?.username || c.user?.username || 'Unknown'}</p>
                    {editingId === c.id ? (
                      <div className="space-y-2 mb-3">
                        <textarea
                          value={editingContent}
                          onChange={(e) => setEditingContent(e.target.value)}
                          className="w-full p-2 border border-gray-300 rounded text-sm"
                          rows="3"
                        />
                        <div className="flex gap-2">
                          <button
                            className="bg-blue-500 hover:bg-blue-600 text-white font-semibold px-3 py-1 rounded text-sm"
                            onClick={() => saveEdit('comment', c.id)}
                          >
                            Lưu
                          </button>
                          <button
                            className="bg-gray-300 hover:bg-gray-400 text-gray-800 font-semibold px-3 py-1 rounded text-sm"
                            onClick={() => setEditingId(null)}
                          >
                            Hủy
                          </button>
                        </div>
                      </div>
                    ) : (
                      <p className="text-gray-800 mb-3 line-clamp-2">{c.content}</p>
                    )}
                    <div className="flex gap-2">
                      <button
                        className="bg-blue-500 hover:bg-blue-600 text-white font-semibold px-3 py-1 rounded text-sm"
                        onClick={() => editComment(c.id, c.content || '')}
                      >
                        Sửa
                      </button>
                      <button
                        className="bg-red-500 hover:bg-red-600 text-white font-semibold px-3 py-1 rounded text-sm"
                        onClick={() => deleteComment(c.id)}
                      >
                        Xóa
                      </button>
                    </div>
                  </div>
                ))
              )}
            </div>
          </div>
        )}

        {/* Messages Tab */}
        {activeTab === 'messages' && (
          <div className="bg-white rounded-2xl shadow-lg overflow-hidden">
            <div className="bg-gradient-to-r from-cyan-500 to-blue-600 px-6 py-4 flex items-center gap-3">
              <svg className="w-6 h-6 text-white" fill="currentColor" viewBox="0 0 20 20">
                <path d="M2.003 5.884L10 9.882l7.997-3.998A2 2 0 0016 4H4a2 2 0 00-1.997 1.884z" />
                <path d="M18 8.118l-8 4-8-4V14a2 2 0 002 2h12a2 2 0 002-2V8.118z" />
              </svg>
              <h2 className="text-2xl font-bold text-white">Quản lý tin nhắn ({messages.length})</h2>
            </div>
            <div className="divide-y divide-gray-200 max-h-96 overflow-y-auto">
              {messages.length === 0 ? (
                <div className="p-8 text-center text-gray-500">
                  <svg className="w-12 h-12 text-gray-300 mx-auto mb-3" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M3 8l7.89 5.26a2 2 0 002.22 0L21 8M5 19h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v10a2 2 0 002 2z" />
                  </svg>
                  Không có tin nhắn
                </div>
              ) : (
                messages.map((m) => (
                  <div key={m.id} className="px-6 py-4 hover:bg-cyan-50 transition-colors">
                    <div className="flex justify-between items-start mb-2">
                      <div>
                        <p className="text-sm text-gray-600 font-semibold">
                          Từ: {m.sender?.username || m.senderUsername || 'Unknown'}
                        </p>
                        <p className="text-sm text-gray-600">
                          Đến: {m.receiver?.username || m.receiverUsername || 'Unknown'}
                        </p>
                      </div>
                      <span className="text-xs text-gray-400">
                        {m.createdAt ? new Date(m.createdAt).toLocaleDateString('vi-VN') : ''}
                      </span>
                    </div>
                    {editingId === m.id ? (
                      <div className="space-y-2 mb-3">
                        <textarea
                          value={editingContent}
                          onChange={(e) => setEditingContent(e.target.value)}
                          className="w-full p-2 border border-gray-300 rounded text-sm"
                          rows="3"
                        />
                        <div className="flex gap-2">
                          <button
                            className="bg-blue-500 hover:bg-blue-600 text-white font-semibold px-3 py-1 rounded text-sm"
                            onClick={() => saveEdit('message', m.id)}
                          >
                            Lưu
                          </button>
                          <button
                            className="bg-gray-300 hover:bg-gray-400 text-gray-800 font-semibold px-3 py-1 rounded text-sm"
                            onClick={() => setEditingId(null)}
                          >
                            Hủy
                          </button>
                        </div>
                      </div>
                    ) : (
                      <p className="text-gray-800 mb-3 line-clamp-3">{m.content || m.message || m.text || '(Không có nội dung)'}</p>
                    )}
                    <div className="flex gap-2">
                      <button
                        className="bg-blue-500 hover:bg-blue-600 text-white font-semibold px-3 py-1 rounded text-sm"
                        onClick={() => editMessage(m.id, m.content || m.message || m.text || '')}
                      >
                        Sửa
                      </button>
                      <button
                        className="bg-red-500 hover:bg-red-600 text-white font-semibold px-3 py-1 rounded text-sm"
                        onClick={() => deleteMessage(m.id)}
                      >
                        Xóa
                      </button>
                    </div>
                  </div>
                ))
              )}
            </div>
          </div>
        )}

        {/* Reports Tab */}
        {activeTab === 'reports' && (
          <div className="bg-white rounded-2xl shadow-lg overflow-hidden">
            <div className="bg-gradient-to-r from-orange-500 to-orange-600 px-6 py-4 flex items-center gap-3">
              <svg className="w-6 h-6 text-white" fill="currentColor" viewBox="0 0 20 20">
                <path fillRule="evenodd" d="M8.257 3.099c.765-1.36 2.722-1.36 3.486 0l5.58 9.92c.75 1.334-.213 2.98-1.742 2.98H4.42c-1.53 0-2.493-1.646-1.743-2.98l5.58-9.92zM11 13a1 1 0 11-2 0 1 1 0 012 0zm-1-8a1 1 0 00-1 1v3a1 1 0 002 0V6a1 1 0 00-1-1z" clipRule="evenodd" />
              </svg>
              <h2 className="text-2xl font-bold text-white">Quản lý báo cáo ({reports.length})</h2>
            </div>
            <div className="divide-y divide-gray-200 max-h-96 overflow-y-auto">
              {reports.length === 0 ? (
                <div className="p-8 text-center text-gray-500">
                  <svg className="w-12 h-12 text-gray-300 mx-auto mb-3" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M12 8v4m0 4v.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
                  </svg>
                  Không có báo cáo
                </div>
              ) : (
                reports.map((r) => (
                  <div key={r.id} className="px-6 py-4 hover:bg-orange-50 transition-colors">
                    <p className="font-semibold text-gray-900 mb-1">Report #{r.id}</p>
                    <p className="text-gray-700 mb-3">{r.reason}</p>
                    <span className={`inline-block px-3 py-1 rounded-full text-xs font-semibold mb-3 ${r.status === 'resolved' || r.resolved ? 'bg-green-100 text-green-700' : 'bg-yellow-100 text-yellow-700'}`}>
                      {r.status === 'resolved' || r.resolved ? 'Đã xử lý' : 'Chưa xử lý'}
                    </span>
                    {(r.status !== 'resolved' && !r.resolved) && (
                      <button
                        className="ml-2 bg-green-500 hover:bg-green-600 text-white font-semibold px-4 py-2 rounded-lg transition-all"
                        onClick={() => resolveReport(r.id)}
                      >
                        Xác nhận xử lý
                      </button>
                    )}
                  </div>
                ))
              )}
            </div>
          </div>
        )}

        {/* Media Tab */}
        {activeTab === 'media' && (
          <div className="bg-white rounded-2xl shadow-lg overflow-hidden">
            <div className="bg-gradient-to-r from-indigo-500 to-indigo-600 px-6 py-4 flex items-center gap-3">
              <svg className="w-6 h-6 text-white" fill="currentColor" viewBox="0 0 20 20">
                <path d="M4 3a2 2 0 00-2 2v10a2 2 0 002 2h12a2 2 0 002-2V5a2 2 0 00-2-2H4zm12 12H4l4-8 3 6 2-4 3 6z" />
              </svg>
              <h2 className="text-2xl font-bold text-white">Quản lý Media</h2>
            </div>
            <div className="p-8 text-center">
              <svg className="w-16 h-16 text-gray-300 mx-auto mb-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" />
              </svg>
              <p className="text-gray-600 text-lg">Tính năng quản lý Media sẽ được cập nhật sớm</p>
              <p className="text-gray-400 mt-2">Có thể xem, xóa hoặc quản lý các tệp media đã tải lên</p>
            </div>
          </div>
        )}
      </div>

      {/* Confirmation Modal */}
      {modal && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 backdrop-blur-sm">
          <div className="bg-white rounded-2xl shadow-2xl w-full max-w-sm p-6 space-y-4 animate-in fade-in zoom-in-95">
            <div className="flex items-center gap-3">
              <svg className="w-6 h-6 text-orange-600" fill="currentColor" viewBox="0 0 20 20">
                <path fillRule="evenodd" d="M8.257 3.099c.765-1.36 2.722-1.36 3.486 0l5.58 9.92c.75 1.334-.213 2.98-1.742 2.98H4.42c-1.53 0-2.493-1.646-1.743-2.98l5.58-9.92zM11 13a1 1 0 11-2 0 1 1 0 012 0zm-1-8a1 1 0 00-1 1v3a1 1 0 002 0V6a1 1 0 00-1-1z" clipRule="evenodd" />
              </svg>
              <p className="text-lg font-semibold text-gray-900">{modal.msg}</p>
            </div>
            <div className="flex gap-3 pt-4">
              <button
                className="flex-1 bg-gradient-to-r from-red-500 to-red-600 hover:from-red-600 hover:to-red-700 text-white font-semibold px-4 py-2 rounded-lg transition-all"
                onClick={() => modal.onYes()}
              >
                Xác nhận
              </button>
              <button
                className="flex-1 bg-gray-300 hover:bg-gray-400 text-gray-800 font-semibold px-4 py-2 rounded-lg transition-all"
                onClick={closeModal}
              >
                Hủy
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
